class Bank {
    constructor(balance) {
        this.balance = balance.slice();
        this.n = balance.length;
    }

    _valid(account) {
        return account >= 1 && account <= this.n;
    }

    transfer(account1, account2, money) {
        if (!this._valid(account1) || !this._valid(account2)) return false;
        if (this.balance[account1 - 1] < money) return false;
        this.balance[account1 - 1] -= money;
        this.balance[account2 - 1] += money;
        return true;
    }

    deposit(account, money) {
        if (!this._valid(account)) return false;
        this.balance[account - 1] += money;
        return true;
    }

    withdraw(account, money) {
        if (!this._valid(account)) return false;
        if (this.balance[account - 1] < money) return false;
        this.balance[account - 1] -= money;
        return true;
    }
}
